using System.ComponentModel;
using System.Net;
using System.Text;
using Microsoft.Extensions.AI;
using OpenAI;

// --- Configuration ---
var apiKey = Environment.GetEnvironmentVariable("OPENAI_API_KEY")
    ?? throw new InvalidOperationException(
        "Set the OPENAI_API_KEY environment variable before running.");

var model = Environment.GetEnvironmentVariable("OPENAI_MODEL") ?? "gpt-4o-mini";

// --- Shared state for the note-taking tool ---
var notes = new List<string>();

// --- Tool definitions ---
var searchWeb = AIFunctionFactory.Create(SearchWebAsync, "search_web",
    "Search the web for information on a query and return top results.");

var saveNote = AIFunctionFactory.Create(SaveNote, "save_note",
    "Save a research note capturing a key finding or insight.");

var readNotes = AIFunctionFactory.Create(ReadNotes, "read_notes",
    "Read all research notes collected so far.");

// --- Build AI client with automatic function invocation ---
IChatClient client = new ChatClientBuilder(
        new OpenAIClient(apiKey).GetChatClient(model).AsIChatClient())
    .UseFunctionInvoking()
    .Build();

var systemPrompt = """
    You are a research agent. Your job is to research a topic provided by the user.

    Follow this workflow:
    1. Break the topic into 2-3 key sub-questions.
    2. Use the search_web tool to find information for each sub-question.
    3. Use the save_note tool to record important facts and findings as you go.
    4. After gathering enough information, use read_notes to review everything.
    5. Provide a well-structured summary with sections, key takeaways, and sources.

    Be thorough but concise. Always cite URLs where possible.
    """;

// --- Interactive loop ---
Console.WriteLine("╔══════════════════════════════════════╗");
Console.WriteLine("║       🔬 AI Research Agent           ║");
Console.WriteLine("╠══════════════════════════════════════╣");
Console.WriteLine("║  Enter a topic to research.          ║");
Console.WriteLine("║  Type 'quit' to exit.                ║");
Console.WriteLine("╚══════════════════════════════════════╝");
Console.WriteLine();

while (true)
{
    Console.ForegroundColor = ConsoleColor.Green;
    Console.Write("Research topic> ");
    Console.ResetColor();

    var topic = Console.ReadLine()?.Trim();
    if (string.IsNullOrEmpty(topic) || topic.Equals("quit", StringComparison.OrdinalIgnoreCase))
        break;

    notes.Clear();

    var messages = new List<ChatMessage>
    {
        new(ChatRole.System, systemPrompt),
        new(ChatRole.User,
            $"Research the following topic and provide a comprehensive summary:\n\n{topic}"),
    };

    Console.WriteLine();
    Console.ForegroundColor = ConsoleColor.DarkGray;
    Console.WriteLine("Researching... (the agent will search the web and take notes)");
    Console.ResetColor();
    Console.WriteLine();

    try
    {
        var response = await client.GetResponseAsync(messages, new ChatOptions
        {
            Tools = [searchWeb, saveNote, readNotes],
        });

        Console.ForegroundColor = ConsoleColor.White;
        Console.WriteLine("═══════════════ Research Summary ═══════════════");
        Console.ResetColor();
        Console.WriteLine();
        Console.WriteLine(response.Text);
        Console.WriteLine();
        Console.ForegroundColor = ConsoleColor.DarkGray;
        Console.WriteLine($"[{notes.Count} notes taken · "
            + $"Tokens: {response.Usage?.InputTokenCount ?? 0} in / "
            + $"{response.Usage?.OutputTokenCount ?? 0} out]");
        Console.ResetColor();
    }
    catch (Exception ex)
    {
        Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Error: {ex.Message}");
        Console.ResetColor();
    }

    Console.WriteLine();
}

Console.WriteLine("Goodbye!");
return;

// ---------------------------------------------------------------------------
// Tool implementations
// ---------------------------------------------------------------------------

[Description("Search the web for information on a query.")]
async Task<string> SearchWebAsync(
    [Description("The search query")] string query,
    CancellationToken cancellationToken = default)
{
    Console.ForegroundColor = ConsoleColor.DarkYellow;
    Console.WriteLine($"  🔍 Searching: \"{query}\"");
    Console.ResetColor();

    using var http = new HttpClient();
    http.DefaultRequestHeaders.UserAgent.ParseAdd(
        "Mozilla/5.0 (compatible; ResearchAgent/1.0)");

    var encoded = WebUtility.UrlEncode(query);
    var url = $"https://html.duckduckgo.com/html/?q={encoded}";

    string html;
    try
    {
        html = await http.GetStringAsync(url, cancellationToken);
    }
    catch (HttpRequestException ex)
    {
        return $"Search failed: {ex.Message}";
    }

    var results = ParseSearchResults(html);
    if (results.Count == 0)
        return "No results found.";

    var sb = new StringBuilder();
    foreach (var (i, r) in results.Take(5).Select((r, i) => (i, r)))
    {
        sb.AppendLine($"[{i + 1}] {r.Title}");
        if (!string.IsNullOrEmpty(r.Url))
            sb.AppendLine($"    URL: {r.Url}");
        if (!string.IsNullOrEmpty(r.Snippet))
            sb.AppendLine($"    {r.Snippet}");
        sb.AppendLine();
    }

    return sb.ToString();
}

[Description("Save a research note.")]
string SaveNote(
    [Description("The note content to save")] string content)
{
    notes.Add(content);
    Console.ForegroundColor = ConsoleColor.DarkCyan;
    Console.WriteLine($"  📝 Note saved (#{notes.Count})");
    Console.ResetColor();
    return $"Note #{notes.Count} saved.";
}

[Description("Read all saved research notes.")]
string ReadNotes()
{
    if (notes.Count == 0)
        return "No notes saved yet.";

    var sb = new StringBuilder();
    for (var i = 0; i < notes.Count; i++)
        sb.AppendLine($"--- Note #{i + 1} ---\n{notes[i]}\n");
    return sb.ToString();
}

// ---------------------------------------------------------------------------
// Minimal HTML parser for DuckDuckGo search results
// ---------------------------------------------------------------------------

static List<SearchResult> ParseSearchResults(string html)
{
    var results = new List<SearchResult>();
    var pos = 0;

    while (results.Count < 8)
    {
        const string linkMarker = "class=\"result__a\"";
        var linkIdx = html.IndexOf(linkMarker, pos, StringComparison.Ordinal);
        if (linkIdx < 0)
            break;

        // Extract href
        var hrefStart = html.LastIndexOf("href=\"", linkIdx, Math.Min(linkIdx, 200),
            StringComparison.Ordinal);
        var resultUrl = "";
        if (hrefStart >= 0)
        {
            hrefStart += 6;
            var hrefEnd = html.IndexOf('"', hrefStart);
            if (hrefEnd > hrefStart)
                resultUrl = WebUtility.HtmlDecode(html[hrefStart..hrefEnd]);
        }

        // Extract title text between > and </a>
        var titleStart = html.IndexOf('>', linkIdx) + 1;
        var titleEnd = html.IndexOf("</a>", titleStart, StringComparison.Ordinal);
        var title = titleStart > 0 && titleEnd > titleStart
            ? StripHtml(html[titleStart..titleEnd])
            : "";

        // Extract snippet
        const string snippetMarker = "class=\"result__snippet\"";
        var snippetIdx = html.IndexOf(snippetMarker, linkIdx, StringComparison.Ordinal);
        var snippet = "";
        if (snippetIdx >= 0 && snippetIdx - linkIdx < 2000)
        {
            var snippetStart = html.IndexOf('>', snippetIdx) + 1;
            var snippetEnd = html.IndexOf("</a>", snippetStart, StringComparison.Ordinal);
            if (snippetEnd < 0)
                snippetEnd = html.IndexOf("</td>", snippetStart, StringComparison.Ordinal);
            if (snippetStart > 0 && snippetEnd > snippetStart)
                snippet = StripHtml(html[snippetStart..snippetEnd]);
        }

        if (!string.IsNullOrWhiteSpace(title))
            results.Add(new SearchResult(title.Trim(), resultUrl.Trim(), snippet.Trim()));

        pos = linkIdx + linkMarker.Length;
    }

    return results;
}

static string StripHtml(string html)
{
    var sb = new StringBuilder(html.Length);
    var inTag = false;
    foreach (var c in html)
    {
        switch (c)
        {
            case '<': inTag = true; break;
            case '>': inTag = false; break;
            default:
                if (!inTag) sb.Append(c);
                break;
        }
    }

    return WebUtility.HtmlDecode(sb.ToString());
}

internal record SearchResult(string Title, string Url, string Snippet);

